#!/usr/bin/env node
/**
 * GovAI Design System — Bundle Generator
 *
 * Reads Design.md, tokens.ts, globals.css, and every component in
 * src/components/ui/ from the local repo and writes govai-design-bundle.md.
 *
 * Run:  node scripts/generate-bundle.js
 * CI:   called automatically by .github/workflows/update-bundle.yml on push to main
 */

import { readFileSync, writeFileSync, readdirSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const OUT = join(ROOT, "govai-design-bundle.md");

function read(relPath) {
  return readFileSync(join(ROOT, relPath), "utf8");
}

// 1. Core files
const designMd = read("Design.md");
const tokensTs = read("src/lib/tokens.ts");
const globalsCss = read("src/app/globals.css");

// 2. Auto-discover all components (excludes .figma.tsx variants)
const componentFiles = readdirSync(join(ROOT, "src/components/ui"))
  .filter((f) => f.endsWith(".tsx") && !f.endsWith(".figma.tsx"))
  .sort();

// 3. Read every component source
const components = componentFiles.map((name) => ({
  name,
  code: read(`src/components/ui/${name}`),
}));

// 4. Assemble bundle
const timestamp = new Date().toISOString();
const lines = [
  "# GovAI Design System — Full Bundle",
  "",
  `> Auto-generated from \`kenavelino/govai-design-system@main\` at ${timestamp}.`,
  "> Do not edit this file manually — it is regenerated on every push to main.",
  "",
  "Paste this into Google AI Studio System Instructions, or any AI tool's context window.",
  "",
  "---",
  "",
  "## 1. Design Principles (Design.md)",
  "",
  designMd,
  "",
  "---",
  "",
  "## 2. Design Tokens (src/lib/tokens.ts)",
  "",
  "```ts",
  tokensTs,
  "```",
  "",
  "---",
  "",
  "## 3. Global Styles (src/app/globals.css)",
  "",
  "```css",
  globalsCss,
  "```",
  "",
  "---",
  "",
  `## 4. UI Components (${components.length} components in src/components/ui/)`,
  "",
  ...components.flatMap(({ name, code }) => [
    `### ${name}`,
    "",
    "```tsx",
    code,
    "```",
    "",
  ]),
];

writeFileSync(OUT, lines.join("\n"), "utf8");

const sizeKb = (readFileSync(OUT).length / 1024).toFixed(1);
console.log(
  `✓ govai-design-bundle.md generated — ${components.length} components, ${sizeKb} KB`
);
